approach_1_expand_center.code:
class Solution:
    def longestPalindrome(self, s: str) -> str:
        def helper(left, right, s):
            while left >= 0 and right < len(s):
                if s[left] == s[right]:
                    left -= 1
                    right += 1
                else:
                    break
            # left went one too far left, right went one too far right
            # palindrome is s[left+1 : right]
            return s[left+1: right]

        result = ""
        for i in range(len(s)):
            c1 = helper(i, i, s)       # odd-length: center at i
            c2 = helper(i, i+1, s)     # even-length: center between i and i+1
            candidate = c1 if len(c1) > len(c2) else c2
            if len(candidate) >= len(result):
                result = candidate
        return result
        # Time: O(n^2) | Space: O(1)

approach_2_brute_force.code:
def longestPalindrome(s):
    n = len(s)
    best = s[0]  # single char is always a palindrome
    for i in range(n):
        for j in range(i+1, n):
            sub = s[i:j+1]
            if sub == sub[::-1] and len(sub) > len(best):
                best = sub
    return best
    # Time: O(n^3) | Space: O(n) for the substring slice

approach_3_dp.code:
def longestPalindrome(s):
    n = len(s)
    dp = [[False] * n for _ in range(n)]
    start, max_len = 0, 1

    # base case: every single character is a palindrome
    for i in range(n):
        dp[i][i] = True

    # base case: check all pairs
    for i in range(n-1):
        if s[i] == s[i+1]:
            dp[i][i+1] = True
            start, max_len = i, 2

    # fill by increasing length (length 3 to n)
    for length in range(3, n+1):
        for i in range(n - length + 1):
            j = i + length - 1
            if s[i] == s[j] and dp[i+1][j-1]:
                dp[i][j] = True
                if length > max_len:
                    start, max_len = i, length

    return s[start : start + max_len]
    # Time: O(n^2) | Space: O(n^2)
